export const NON_EXAM_TOPICS = ['gk', 'apt'];
export const isNonExamTopic = (topicId) => NON_EXAM_TOPICS.indexOf(topicId) !== -1;
// True when a topic should be counted in NURSING analytics. Non-exam topics
// count only when the user explicitly opts in (preferences.includeGkInStats).
export const countsInNursingStats = (topicId, includeGk) => !!includeGk || !isNonExamTopic(topicId);

